# Create runtime directories
$rd = Join-Path $targetDir 'results'
if (-not (Test-Path $rd)) {
    New-Item -ItemType Directory -Path $rd -Force | Out-Null
    Write-Host '  [OK] results/ (directory)' -ForegroundColor Green
}
$id = Join-Path $targetDir 'imported-decks'
if (-not (Test-Path $id)) {
    New-Item -ItemType Directory -Path $id -Force | Out-Null
    Write-Host '  [OK] imported-decks/ (directory)' -ForegroundColor Green
}
$dr = Join-Path $targetDir 'deck-reports'
if (-not (Test-Path $dr)) {
    New-Item -ItemType Directory -Path $dr -Force | Out-Null
    Write-Host '  [OK] deck-reports/ (directory)' -ForegroundColor Green
}
$cs = Join-Path $targetDir 'coach-sessions'
if (-not (Test-Path $cs)) {
    New-Item -ItemType Directory -Path $cs -Force | Out-Null
    Write-Host '  [OK] coach-sessions/ (directory)' -ForegroundColor Green
}
$em = Join-Path $targetDir 'embeddings'
if (-not (Test-Path $em)) {
    New-Item -ItemType Directory -Path $em -Force | Out-Null
    Write-Host '  [OK] embeddings/ (directory)' -ForegroundColor Green
}
$mc = Join-Path $targetDir 'ml\models\checkpoints'
if (-not (Test-Path $mc)) {
    New-Item -ItemType Directory -Path $mc -Force | Out-Null
    Write-Host '  [OK] ml/models/checkpoints/ (directory)' -ForegroundColor Green
}
$ld = Join-Path $targetDir 'logs\decisions'
if (-not (Test-Path $ld)) {
    New-Item -ItemType Directory -Path $ld -Force | Out-Null
    Write-Host '  [OK] logs/decisions/ (directory)' -ForegroundColor Green
}

Write-Host ''
Write-Host '=======================================================' -ForegroundColor Cyan
Write-Host '  All 174 files installed successfully!' -ForegroundColor Green
Write-Host '=======================================================' -ForegroundColor Cyan
Write-Host ''
Write-Host '  Checking prerequisites...' -ForegroundColor White

$javaOk = $false
try {
    $jv = & java -version 2>&1 | Select-Object -First 1
    Write-Host ('    Java:   ' + $jv) -ForegroundColor Green
    $javaOk = $true
} catch {
    Write-Host '    Java:   NOT FOUND - Install Java 17+' -ForegroundColor Red
}

$pythonOk = $false
try {
    $pv = & python --version 2>&1
    Write-Host ('    Python: ' + $pv) -ForegroundColor Green
    $pythonOk = $true
} catch {
    Write-Host '    Python: NOT FOUND - Install Python 3.10+' -ForegroundColor Red
}

$mvnOk = $false
try {
    $mv = & mvn --version 2>&1 | Select-Object -First 1
    Write-Host ('    Maven:  ' + $mv) -ForegroundColor Green
    $mvnOk = $true
} catch {
    Write-Host '    Maven:  NOT FOUND - Install Maven 3.8+' -ForegroundColor Red
}

$forgeJar = 'D:\ForgeCommander\forge-repo\forge-gui-desktop\target\forge-gui-desktop-2.0.12-SNAPSHOT-jar-with-dependencies.jar'
if (Test-Path $forgeJar) {
    Write-Host '    Forge:  Found' -ForegroundColor Green
} else {
    Write-Host '    Forge:  JAR not found at expected path' -ForegroundColor Yellow
    Write-Host '            Build Forge first:' -ForegroundColor Yellow
    Write-Host '              cd D:\ForgeCommander\forge-repo' -ForegroundColor White
    Write-Host '              mvn install -pl forge-core,forge-game,forge-ai "-DskipTests" "-Drevision=2.0.12-SNAPSHOT"' -ForegroundColor White
    Write-Host '              mvn package -pl forge-gui-desktop "-DskipTests" "-Drevision=2.0.12-SNAPSHOT" -am' -ForegroundColor White
}

$nodeOk = $false
try {
    $nv = & node --version 2>&1
    Write-Host ('    Node.js: ' + $nv) -ForegroundColor Green
    $nodeOk = $true
} catch {
    Write-Host '    Node.js: NOT FOUND - Install Node.js 18+ from https://nodejs.org' -ForegroundColor Red
}

$m2 = Join-Path $env:USERPROFILE '.m2\repository\forge\forge-core\2.0.12-SNAPSHOT\forge-core-2.0.12-SNAPSHOT.jar'
if (Test-Path $m2) {
    Write-Host '    Forge Maven artifacts: Found in .m2' -ForegroundColor Green
} else {
    Write-Host '    Forge Maven artifacts: NOT FOUND in .m2' -ForegroundColor Yellow
    Write-Host '            Run: cd D:\ForgeCommander\forge-repo' -ForegroundColor White
    Write-Host '            mvn install -pl forge-core,forge-game,forge-ai "-DskipTests" "-Drevision=2.0.12-SNAPSHOT"' -ForegroundColor White
}

Write-Host ''
Write-Host '  UI: Using HTML/JS/CSS interface (ui/ folder)' -ForegroundColor Green

Write-Host ''
if ($pythonOk) {
    $fc = & python -c 'import fastapi' 2>&1
    if ($LASTEXITCODE -ne 0) {
        Write-Host '  Installing Python dependencies...' -ForegroundColor Yellow
        pip install fastapi uvicorn python-multipart
    } else {
        Write-Host '  Python deps: fastapi already installed' -ForegroundColor Green
    }
    Write-Host ''
    Write-Host '  Installing Python simulator package (editable)...' -ForegroundColor Yellow
    Push-Location $targetDir
    try {
        pip install -e . 2>&1 | Out-Null
        if ($LASTEXITCODE -eq 0) {
            Write-Host '    commander_ai_lab package installed' -ForegroundColor Green
            Write-Host '    CLI command available: commander-sim' -ForegroundColor Green
        } else {
            Write-Host '    pip install -e . failed (non-critical)' -ForegroundColor Yellow
        }
    } catch {
        Write-Host '    pip install -e . failed (non-critical)' -ForegroundColor Yellow
    } finally {
        Pop-Location
    }
    Write-Host ''
    Write-Host '  Card Scanner: Uses Ximilar Visual AI (no local deps needed)' -ForegroundColor Green
    Write-Host '    API key is pre-configured in start-lab.bat' -ForegroundColor Gray
    Write-Host ''
    Write-Host '  Installing Coach dependencies...' -ForegroundColor Yellow
    pip install numpy pydantic pandas pyarrow openai 2>&1 | Out-Null
    Write-Host '    Coach deps (numpy, pydantic, pandas, pyarrow, openai) installed' -ForegroundColor Green
    Write-Host '    NOTE: LM Studio must be running on 192.168.0.122:1234 for AI coaching' -ForegroundColor Gray
    Write-Host '    Embeddings will auto-download on first coach session (~50MB)' -ForegroundColor Gray
    Write-Host ''
    Write-Host '  Installing ML training dependencies...' -ForegroundColor Yellow
    pip install torch --index-url https://download.pytorch.org/whl/cu126 2>&1 | Out-Null
    Write-Host '    PyTorch (CUDA 12.6) installed for policy training' -ForegroundColor Green
    Write-Host '    CPU-only alternative: pip install torch --index-url https://download.pytorch.org/whl/cpu' -ForegroundColor Gray
}

Write-Host ''
Write-Host '=======================================================' -ForegroundColor Cyan
Write-Host '  Setup Guide' -ForegroundColor Cyan
Write-Host '=======================================================' -ForegroundColor Cyan
Write-Host ''
Write-Host '  Step 1: Install Forge modules to local Maven repo (if not done)' -ForegroundColor Yellow
Write-Host '    cd D:\ForgeCommander\forge-repo' -ForegroundColor White
Write-Host '    mvn install -pl forge-core,forge-game,forge-ai "-DskipTests" "-Drevision=2.0.12-SNAPSHOT"' -ForegroundColor White
Write-Host ''
Write-Host '  Step 2: Build Commander AI Lab' -ForegroundColor Yellow
Write-Host ('    cd ' + $targetDir) -ForegroundColor White
Write-Host '    mvn package "-DskipTests"' -ForegroundColor White
Write-Host ''
Write-Host '  Step 3: Launch the server' -ForegroundColor Yellow
Write-Host '    Option A: .\start-lab.bat' -ForegroundColor White
Write-Host '    Option B: python lab_api.py --forge-jar D:\ForgeCommander\forge-repo\forge-gui-desktop\target\forge-gui-desktop-2.0.12-SNAPSHOT-jar-with-dependencies.jar --forge-dir D:\ForgeCommander\forge-repo\forge-gui --port 8080' -ForegroundColor White
Write-Host ''
Write-Host '  Step 4: Open http://localhost:8080 in your browser' -ForegroundColor Yellow
Write-Host '    All pages load from the ui/ folder (Collection, Decks, Auto Gen, Coach, etc.)' -ForegroundColor Gray
Write-Host ''
Write-Host '  Python Simulator (no Forge needed):' -ForegroundColor Cyan
Write-Host '    python -m commander_ai_lab.lab.experiments' -ForegroundColor White
Write-Host '    Or after pip install -e .:  commander-sim' -ForegroundColor White
Write-Host ''
Write-Host '  Deck Coach (LLM-powered):' -ForegroundColor Cyan
Write-Host '    1. Start LM Studio with a model loaded on 192.168.0.122:1234' -ForegroundColor White
Write-Host '    2. Run simulations to generate deck reports' -ForegroundColor White
Write-Host '    3. Open http://localhost:8080/coach' -ForegroundColor White
Write-Host '    Embeddings (~50MB) auto-download on first use' -ForegroundColor Gray
Write-Host ''
Write-Host '  DeepSeek AI Opponent:' -ForegroundColor Cyan
Write-Host '    1. Start LM Studio with DeepSeek-R1 8B loaded on 192.168.0.122:1234' -ForegroundColor White
Write-Host '    2. Open Simulator page, select DeepSeek AI as opponent' -ForegroundColor White
Write-Host '    3. Click Connect, then Run Simulation' -ForegroundColor White
Write-Host '    Decision logs saved to logs/decisions/ for future training' -ForegroundColor Gray
Write-Host ''
Write-Host '  Perplexity AI (Deck Research + Generation):' -ForegroundColor Cyan
Write-Host '    Set env var: $env:PPLX_API_KEY = your-key' -ForegroundColor White
Write-Host '    Or pass: python lab_api.py --pplx-key your-key ...' -ForegroundColor White
Write-Host '    AI panels appear on Deck Builder page when key is configured' -ForegroundColor Gray
Write-Host ''
Write-Host '  ML Training Pipeline:' -ForegroundColor Cyan
Write-Host '    1. Generate synthetic data (or run real sims with ML logging):' -ForegroundColor White
Write-Host '       python -m ml.scripts.generate_synthetic_data --games 500' -ForegroundColor Gray
Write-Host '    2. Build dataset:  python -m ml.scripts.ml_cli build' -ForegroundColor White
Write-Host '    3. Train policy:   python -m ml.scripts.ml_cli train' -ForegroundColor White
Write-Host '    4. Evaluate:       python -m ml.scripts.ml_cli eval' -ForegroundColor White
Write-Host '    5. Check status:   python -m ml.scripts.ml_cli status' -ForegroundColor White
Write-Host '    Training uses GPU (CUDA) automatically if available' -ForegroundColor Gray
Write-Host ''
if ($javaOk -and $mvnOk) {
    $bc = Read-Host '  Build Commander AI Lab now? (mvn package -DskipTests) [Y/n]' 
    if ($bc -ne 'n' -and $bc -ne 'N') {
        Write-Host ''
        Write-Host '  Building Commander AI Lab...' -ForegroundColor Yellow
        Push-Location $targetDir
        try {
            mvn package "-DskipTests"
            if ($LASTEXITCODE -eq 0) {
                Write-Host ''
                Write-Host '  Build successful!' -ForegroundColor Green
                $sj = Get-ChildItem -Path (Join-Path $targetDir 'target') -Filter 'commander-ai-lab-*-shaded.jar' -ErrorAction SilentlyContinue | Where-Object { -not $_.Name.StartsWith('original-') } | Select-Object -First 1
                if ($sj) {
                    Write-Host ('  Lab JAR: ' + $sj.FullName + ' (' + [math]::Round($sj.Length / 1MB, 1) + ' MB)') -ForegroundColor Green
                }
            } else {
                Write-Host ''
                Write-Host ('  Build failed (exit code ' + $LASTEXITCODE + ')') -ForegroundColor Red
                Write-Host '  Make sure Forge modules are installed to local Maven repo first.' -ForegroundColor Yellow
            }
        } finally {
            Pop-Location
        }
    }
} else {
    Write-Host '  Skipping build (Java or Maven not found)' -ForegroundColor Yellow
}

Write-Host ''
Read-Host 'Press Enter to exit'